#!/usr/bin/env -S npx ts-node -r tsconfig-paths/register
/**
 * Example: List Databricks clusters with pagination
 *
 * This example demonstrates:
 * - Listing all clusters in a workspace
 * - Using async iteration for automatic pagination
 * - Filtering clusters by state
 * - Displaying cluster information
 *
 * Prerequisites:
 * - DATABRICKS_HOST environment variable
 * - Valid authentication (PAT, OAuth M2M, or other)
 *
 * Usage:
 *   npx ts-node examples/workspace/clusters/list-clusters.ts
 */

import {WorkspaceClient} from "@databricks/sdk-experimental";

async function main() {
    const client = new WorkspaceClient({});

    console.log("Listing all clusters in workspace...\n");

    try {
        // Collect all clusters
        const clusters = [];
        for await (const cluster of client.clusters.list({})) {
            clusters.push({
                "Name": cluster.cluster_name || "(unnamed)",
                "ID": cluster.cluster_id,
                "State": cluster.state,
                "Spark Version": cluster.spark_version,
                "Node Type": cluster.node_type_id,
                "Workers":
                    cluster.num_workers !== undefined
                        ? cluster.num_workers
                        : "autoscaling",
                "Auto-term (min)":
                    cluster.autotermination_minutes || "disabled",
            });
        }

        if (clusters.length === 0) {
            console.log("No clusters found in workspace.");
        } else {
            console.table(clusters);
            console.log(`\n✓ Found ${clusters.length} cluster(s)`);
        }

        // Example: Filter clusters by state
        console.log("\n--- Running Clusters Only ---\n");

        const runningClusters = clusters.filter((c) => c.State === "RUNNING");

        if (runningClusters.length > 0) {
            console.table(
                runningClusters.map((c) => ({
                    "Name": c.Name,
                    "ID": c.ID,
                    "Spark Version": c["Spark Version"],
                }))
            );
        }

        console.log(`✓ Found ${runningClusters.length} running cluster(s)`);
    } catch (error) {
        console.error(`✗ Error:`, error);
        process.exit(1);
    }
}

main();
